// ─── Card Node ────────────────────────────────────────────────────────────────

function CardNode({ data }) {
  return (
    <div style={{
      background: data.bg,
      border: `2px solid ${data.border}`,
      borderRadius: 12,
      padding: '12px 16px',
      minWidth: 200,
      maxWidth: 220,
      fontFamily: 'Inter, Segoe UI, sans-serif',
      boxShadow: '0 4px 12px rgba(0,0,0,0.4)',
    }}>
      <Handle type="target" position={Position.Left}  style={{ background: data.border, width: 10, height: 10 }} />
      <Handle type="source" position={Position.Right} style={{ background: data.border, width: 10, height: 10 }} />

      {/* Icon + Title */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
        <span style={{ fontSize: 20 }}>{data.icon}</span>
        <span style={{ fontWeight: 700, fontSize: 13, color: data.titleColor }}>{data.title}</span>
      </div>

      {/* Divider */}
      <div style={{ borderTop: `1px solid ${data.border}`, marginBottom: 8, opacity: 0.5 }} />

      {/* Lines */}
      {data.lines.map((line, i) => (
        <div key={i} style={{ fontSize: 11, color: data.lineColor, marginBottom: 3, lineHeight: 1.4 }}>
          {line}
        </div>
      ))}
    </div>
  );
}

